import com.pinterest.ktlint.test.KtLintAssertThat
import org.junit.jupiter.api.Test

class PropertyNamingRuleCustomGetterWithModifiersTest {
    private val propertyNamingRuleAssertThat =
        KtLintAssertThat.assertThatRule { PropertyNamingRule() }

    @Test
    fun `Given an extension property with annotated custom getter then do not emit`() {
        val code =
            """
            class Context
            annotation class SuppressLint(val value: String)

            val Context.adsDelegateFactory @SuppressLint("WrongConstant") get() = Any()
            """.trimIndent()

        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given an extension property with private custom getter then do not emit`() {
        val code =
            """
            class Context

            val Context.adsDelegateFactoryWithPrivateGetter private get() = Any()
            """.trimIndent()

        propertyNamingRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a top level val with default getter with modifier then do emit`() {
        val code =
            """
            class Foo

            val foo = Foo()
                private get
            """.trimIndent()

        @Suppress("ktlint:argument-list-wrapping", "ktlint:max-line-length")
        propertyNamingRuleAssertThat(code)
            .hasLintViolationWithoutAutoCorrect(3, 5, "Property name should use the screaming snake case notation when the value can not be changed")
    }
}
"}

